import{_ as t,o as a,c as i,a2 as o}from"./chunks/framework.D5wUhsuj.js";const u=JSON.parse('{"title":"Application Authentication","description":"","frontmatter":{},"headers":[],"relativePath":"admin/application_authentication.md","filePath":"admin/application_authentication.md","lastUpdated":1783543014000}'),n={name:"admin/application_authentication.md"};function r(l,e,s,c,p,d){return a(),i("div",null,[...e[0]||(e[0]=[o(`<h1 id="application-authentication" tabindex="-1">Application Authentication <a class="header-anchor" href="#application-authentication" aria-label="Permalink to &quot;Application Authentication&quot;">​</a></h1><p>Custom applications can either rely on prokube gateway authentication or implement their own OIDC flow against Keycloak. Choose one pattern deliberately; mixing both without a clear boundary causes redirect loops and confusing authorization failures.</p><h2 id="gateway-authentication" tabindex="-1">Gateway Authentication <a class="header-anchor" href="#gateway-authentication" aria-label="Permalink to &quot;Gateway Authentication&quot;">​</a></h2><p>For internal tools and simple web applications, the usual pattern is to put the application behind the authenticated platform gateway. The gateway handles login and forwards requests to the application after authentication.</p><p>Depending on the deployment, identity information can be forwarded in headers such as:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>kubeflow-userid: user@example.com</span></span>
<span class="line"><span>kubeflow-groups: group-a,group-b</span></span></code></pre></div><p>Treat these headers as trusted only when they are injected by the platform gateway and cannot be supplied directly by the client. Do not expose the backend Service publicly in a way that lets clients forge identity headers.</p><p>Use this pattern when:</p><ul><li>the app only needs to know the authenticated user or groups;</li><li>the app does not need its own login screen or session management;</li><li>platform-level access control is sufficient;</li><li>logout and token refresh behavior can be owned by the platform gateway.</li></ul><h2 id="direct-oidc" tabindex="-1">Direct OIDC <a class="header-anchor" href="#direct-oidc" aria-label="Permalink to &quot;Direct OIDC&quot;">​</a></h2><p>Use direct OIDC when the application has its own authentication module, session handling, callback URLs, or fine-grained authorization model.</p><p>High-level setup:</p><ol><li>Create a client in the prokube Keycloak realm.</li><li>Configure exact redirect URIs and web origins for the application URL.</li><li>Store the client secret outside source code.</li><li>Configure the application with the Keycloak issuer or discovery URL.</li><li>Map required claims and groups.</li><li>Decide whether the gateway should require platform login before the app sees traffic, or whether the app&#39;s OIDC flow is the primary authentication mechanism.</li></ol><p>Common OIDC endpoints are available from the realm discovery document:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://&lt;your-prokube-domain&gt;/auth/realms/&lt;realm&gt;/.well-known/openid-configuration</span></span></code></pre></div><p>Realm names and paths are deployment-specific. Use the Keycloak console for the exact issuer URL.</p><h2 id="groups-and-claims" tabindex="-1">Groups and Claims <a class="header-anchor" href="#groups-and-claims" aria-label="Permalink to &quot;Groups and Claims&quot;">​</a></h2><p>Group formats can differ between header-based authentication and direct OIDC tokens. Header values may be comma-separated, while token claims may use arrays, role prefixes, or nested claim names depending on Keycloak mappers.</p><p>When authorizing inside an application:</p><ul><li>validate the exact claims in a test token;</li><li>keep group names configurable;</li><li>require re-login after group changes;</li><li>avoid hard-coding broad admin groups unless the platform team owns the mapping.</li></ul><h2 id="security-notes" tabindex="-1">Security Notes <a class="header-anchor" href="#security-notes" aria-label="Permalink to &quot;Security Notes&quot;">​</a></h2><ul><li>Never trust user identity headers unless the request came through the trusted gateway path.</li><li>Use HTTPS redirect URIs.</li><li>Store client secrets in Kubernetes Secrets or an external secret manager.</li><li>Use least-privilege groups and scopes.</li><li>Avoid putting tokens in URLs or logs.</li><li>Document who owns client-secret rotation and app authorization rules.</li></ul><h2 id="troubleshooting" tabindex="-1">Troubleshooting <a class="header-anchor" href="#troubleshooting" aria-label="Permalink to &quot;Troubleshooting&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Symptom</th><th>Check</th></tr></thead><tbody><tr><td>Redirect loop</td><td>Gateway auth and application OIDC may both be trying to own login. Check route and auth policies.</td></tr><tr><td><code>invalid redirect_uri</code></td><td>The app callback URL must exactly match the Keycloak client configuration.</td></tr><tr><td>Groups missing</td><td>Check Keycloak mappers and sign in again to refresh token claims.</td></tr><tr><td>403 from gateway</td><td>The route may require a platform auth exemption or an AuthorizationPolicy update.</td></tr><tr><td>Headers missing</td><td>Confirm the request path goes through the authenticated gateway, not directly to the Service.</td></tr></tbody></table><h2 id="related-pages" tabindex="-1">Related Pages <a class="header-anchor" href="#related-pages" aria-label="Permalink to &quot;Related Pages&quot;">​</a></h2><ul><li><a href="./application_networking.html">Application Networking</a></li><li><a href="./identity_providers.html">Identity Providers</a></li><li><a href="./user_management.html">User Management</a></li></ul>`,26)])])}const m=t(n,[["render",r]]);export{u as __pageData,m as default};
